/**
 * South Dakota CFRS (Campaign Finance Reporting System) PDF-based donor ingest.
 *
 * Reads pre-scraped aggregate contribution data from /tmp/sd_contributions.json
 * (generated by running python3 /tmp/sd_scraper.py, which downloads year-end
 * and pre-general 2024 PDF reports from sdcfr.sdsos.gov and extracts aggregate
 * amounts from the INCOME TOTALS section).
 *
 * Note: SD CFRS stores itemized contribution details only in scanned image PDFs.
 * This ingest uses aggregate-level totals from digital report forms, which means
 * the classification is by contribution category (individual vs. entity vs. PAC)
 * rather than per-contributor. This is a limitation of the SD reporting system.
 *
 * To regenerate the JSON:
 *   pip3 install pdfminer.six
 *   python3 /tmp/sd_scraper.py
 *
 * Usage:
 *   DATABASE_URL=<neon> npx tsx scripts/ingest/sd-cfrs-donors.ts [--dry-run]
 */

import * as fs from "node:fs";
import { requireDb } from "../../db/client";
import { candidates, donorAggregates } from "../../db/schema";
import { sql } from "drizzle-orm";
import type { DonorBucketLabel } from "./_bucket-mapping";

const SOURCE = "sd_cfrs_bulk";
const SOURCE_URL = "https://sdcfr.sdsos.gov/Search/Search.aspx";
const ELECTION_CYCLE = "2024";
const DATA_FILE = "/tmp/sd_contributions.json";

const DRY_RUN = process.argv.includes("--dry-run");

function norm(s: string): string {
  return s.toUpperCase().replace(/['']/g, "").replace(/[-]/g, " ").replace(/\s+/g, " ").trim();
}

async function main() {
  const db = requireDb();
  console.log(`[sd-cfrs] starting dryRun=${DRY_RUN}`);

  if (!fs.existsSync(DATA_FILE)) {
    console.error(`[sd-cfrs] data file not found: ${DATA_FILE}`);
    console.error(`[sd-cfrs] run: python3 /tmp/sd_scraper.py`);
    process.exit(1);
  }

  const scraped = JSON.parse(fs.readFileSync(DATA_FILE, "utf-8")) as Record<string, Record<string, number>>;
  console.log(`[sd-cfrs] scraped_candidates=${Object.keys(scraped).length}`);

  const dbCandidates = await db
    .select({ id: candidates.id, fullName: candidates.fullName })
    .from(candidates)
    .where(sql`jurisdiction LIKE 'state-SD-%'`);

  console.log(`[sd-cfrs] db_candidates=${dbCandidates.length}`);

  const candByNorm = new Map(dbCandidates.map(c => [norm(c.fullName), c.id]));

  const upsertRows: Array<{ candidateId: string; bucketLabel: DonorBucketLabel; amountTotal: number }> = [];
  let matched = 0;

  for (const [scrapedName, buckets] of Object.entries(scraped)) {
    const candidateId = candByNorm.get(norm(scrapedName));
    if (!candidateId) {
      console.log(`[sd-cfrs] WARNING unmatched: ${scrapedName}`);
      continue;
    }
    matched++;
    for (const [bucket, total] of Object.entries(buckets)) {
      if (total <= 0) continue;
      upsertRows.push({ candidateId, bucketLabel: bucket as DonorBucketLabel, amountTotal: total });
    }
  }

  console.log(`[sd-cfrs] matched=${matched} rows_to_upsert=${upsertRows.length}`);

  if (DRY_RUN || upsertRows.length === 0) {
    console.log(`[sd-cfrs] dry_run — skipping upsert`);
    upsertRows.slice(0, 10).forEach(r => {
      const name = dbCandidates.find(c => c.id === r.candidateId)?.fullName ?? r.candidateId;
      console.log(`  ${name} | ${r.bucketLabel} | $${r.amountTotal.toFixed(2)}`);
    });
    return;
  }

  let upserted = 0;
  for (const row of upsertRows) {
    await db
      .insert(donorAggregates)
      .values({
        candidateId: row.candidateId,
        electionCycle: ELECTION_CYCLE,
        bucketLabel: row.bucketLabel,
        amountTotal: row.amountTotal.toFixed(2),
        source: SOURCE,
        sourceUrl: SOURCE_URL,
        insertedAt: new Date(),
      })
      .onConflictDoUpdate({
        target: [donorAggregates.candidateId, donorAggregates.electionCycle, donorAggregates.bucketLabel],
        set: {
          amountTotal: sql`excluded.amount_total`,
          source: sql`excluded.source`,
          sourceUrl: sql`excluded.source_url`,
          insertedAt: sql`excluded.inserted_at`,
        },
      });
    upserted++;
  }

  console.log(`[sd-cfrs] complete matched=${matched} rows_upserted=${upserted} dry_run=${DRY_RUN}`);
}

main().catch(err => { console.error(err); process.exit(1); });
